#include <stdio.h>
#include <stdbool.h>
#define MAX_M 30
#define MAX_N 30

bool isSafe(int board[MAX_M][MAX_N], int m, int n, int row, int col) {
    int knight_moves[][2] = {{-2, -1}, {-2, 1}, {-1, -2}, {-1, 2}, {1, -2}, {1, 2}, {2, -1}, {2, 1}};
    for (int i = 0; i < 8; i++) {
        int new_row = row + knight_moves[i][0];
        int new_col = col + knight_moves[i][1];
        if (new_row >= 0 && new_row < m && new_col >= 0 && new_col < n && board[new_row][new_col] == 1) {
            return false;
        }
    }
    return true;
}

int place_knights(int board[MAX_M][MAX_N], int m, int n, int row, int col, int count) {
    if (row == m) {
        return count;
    }
    if (col == n) {
        return place_knights(board, m, n, row + 1, 0, count);
    }
    if (board[row][col] == -1) {
        return place_knights(board, m, n, row, col + 1, count);
    }
    if (isSafe(board, m, n, row, col)) {
        board[row][col] = 1;
        int new_count = place_knights(board, m, n, row, col + 1, count + 1);
        board[row][col] = 0;
        return new_count;
    }
    return place_knights(board, m, n, row, col + 1, count);
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int m, n;
        scanf("%d %d", &m, &n);
        int board[MAX_M][MAX_N];
        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                char c;
                scanf(" %c", &c);
                if (c == '.') {
                    board[i][j] = 0;
                } else {
                    board[i][j] = -1;
                }
            }
        }
        printf("%d\n", place_knights(board, m, n, 0, 0, 0));
    }
    return 0;
}

